import { useLocation, useNavigate } from "react-router-dom";

function LibrarianDashboard() {
  const location = useLocation();
  const navigate = useNavigate();

  const genre = location.state?.genre || "Unknown";

  return (
    <div className="dashboard-page">
      <h1 className="dashboard-title">
        Managing Genre: {genre}
      </h1>

      <div className="dashboard-column">
        <div className="dash-card" onClick={() => navigate(`/librarian/books/${genre}`)}>
          📚 View {genre} Books
        </div>

        <div className="dash-card" onClick={() => navigate(`/librarian/add-book/${genre}`)}>
          ➕ Add New Book
        </div>

        <div className="dash-card" onClick={() => navigate(`/librarian/remove-book/${genre}`)}>
          ❌ Remove Book
        </div>

        <div className="dash-card" onClick={() => navigate(`/librarian/issued/${genre}`)}>
          🕘 Issued Books
        </div>
      </div>
    </div>
  );
}

export default LibrarianDashboard;
